import React, { useState, useEffect } from 'react';
import './App.css';
import Topo from "./componentes/Topo";
import Rodape from "./componentes/Rodape";

function App() {
  const [produtos, setProdutos] = useState([]);
  const [carrinho, setCarrinho] = useState([]);
  const [etapa, setEtapa] = useState('vitrine');
  const [modoCadastro, setModoCadastro] = useState(false);
  const [usuario, setUsuario] = useState(null);
  const [formaPagamento, setFormaPagamento] = useState('');
  const [pedidoFinalizado, setPedidoFinalizado] = useState(null);
  const [formData, setFormData] = useState({ nome: '', email: '', senha: '', telefone: '', cep: '', endereco: '', cpf: '' });
  const [historico, setHistorico] = useState([]);
  const [carregandoHistorico, setCarregandoHistorico] = useState(false);

  useEffect(() => {
    fetch("http://localhost:3001/produtos")
      .then(res => res.json())
      .then(d => setProdutos(d))
      .catch(err => console.error("Erro ao carregar produtos:", err));
  }, []);

  const alterarQuantidade = (id, delta) => {
    setCarrinho(carrinho.map(item => {
      if (item.id === id) {
        const novaQtd = item.qtd + delta;
        return novaQtd > 0 ? { ...item, qtd: novaQtd } : item;
      }
      return item;
    }).filter(item => item.qtd > 0));
  };

  const removerDoCarrinho = (id) => {
    setCarrinho(carrinho.filter(item => item.id !== id));
  };

  const totalProd = carrinho.reduce((acc, i) => acc + (i.valor * i.qtd), 0);
  const valorFrete = formaPagamento === 'pix' ? 0 : 15.00;

  // --- FUNÇÕES ASSÍNCRONAS (CORRIGIDAS) ---

  const handleAuth = async () => {
    const rota = modoCadastro ? 'cadastrar' : 'login';
    try {
      const response = await fetch(`http://localhost:3001/${rota}`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(formData)
      });
      const dados = await response.json();
      if (response.ok) {
        setUsuario(dados);
        setEtapa('checkout');
      } else {
        alert(dados.message || "Erro na autenticação");
      }
    } catch (err) {
      alert("Erro de conexão com o servidor.");
    }
  };

  const verHistorico = async () => {
    if (!usuario) {
      setEtapa('login');
      return;
    }
    setCarregandoHistorico(true);
    try {
      const response = await fetch(`http://localhost:3001/historico/${usuario.id}`);
      const dados = await response.json();
      setHistorico(dados);
      setEtapa('historico');
    } catch (err) {
      alert("Erro ao carregar histórico.");
    } finally {
      setCarregandoHistorico(false);
    }
  };

  const finalizar = async () => {
    if (!usuario || !usuario.id) return alert("Faça login novamente.");
    const novoNumeroPedido = Math.floor(Math.random() * 100000);
    try {
      for (const item of carrinho) {
        const corpoVenda = {
          id_pedido: novoNumeroPedido,
          id_cliente: usuario.id,
          produto: item.produto,
          quantidade: item.qtd || 1,
          valor: item.valor,
          id_produto: item.id
        };
        await fetch("http://localhost:3001/venda_cliente", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(corpoVenda)
        });
      }
      setPedidoFinalizado({ numero: novoNumeroPedido });
      setEtapa('sucesso');
      setCarrinho([]);
    } catch (err) {
      alert("Falha no Pedido: " + err.message);
    }
  };

  return (
    <div className="App">
      {/* CORREÇÃO DO ERRO DE TELA BRANCA AQUI */}
      <Topo 
        totalItens={carrinho.length} 
        abrirCarrinho={() => setEtapa('carrinho')} 
        temPedido={!!pedidoFinalizado} 
        verHistorico={verHistorico} 
        usuarioLogado={!!usuario}
      />

      <main className="conteudo-principal">
        {etapa === 'vitrine' && (
          <div className="grid-produtos">
            {produtos.map(p => (
              <div key={p.id} className="card">
                <img src={p.imagem_url} alt={p.produto} />
                <h3>{p.produto}</h3>
                <p>R$ {parseFloat(p.valor).toFixed(2)}</p>
                <button onClick={() => { setCarrinho([...carrinho, {...p, qtd:1}]); setEtapa('carrinho'); }}>Comprar</button>
              </div>
            ))}
          </div>
        )}

        {etapa === 'carrinho' && (
          <div className="container-venda">
            <h2>🛒 Carrinho</h2>
            {carrinho.map(i => (
              <div key={i.id} className="item-carrinho-detalhado">
                <span>{i.produto} (x{i.qtd})</span>
                <button onClick={() => removerDoCarrinho(i.id)}>🗑️</button>
              </div>
            ))}
            <h3>Total: R$ {totalProd.toFixed(2)}</h3>
            <button className="btn-p" onClick={() => setEtapa('login')}>Finalizar</button>
          </div>
        )}

        {etapa === 'login' && (
          <div className="container-venda">
            <h2>{modoCadastro ? "Cadastro" : "Login"}</h2>
            <input placeholder="E-mail" onChange={e => setFormData({...formData, email: e.target.value})} />
            <input type="password" placeholder="Senha" onChange={e => setFormData({...formData, senha: e.target.value})} />
            <button className="btn-p" onClick={handleAuth}>Confirmar</button>
            <p onClick={() => setModoCadastro(!modoCadastro)}>Trocar Login/Cadastro</p>
          </div>
        )}

        {etapa === 'checkout' && (
          <div className="container-venda">
            <h2>Pagamento para {usuario?.nome}</h2>
            <select onChange={e => setFormaPagamento(e.target.value)}>
              <option value="">Selecione...</option>
              <option value="pix">Pix</option>
              <option value="cartao">Cartão</option>
            </select>
            <button className="btn-p" onClick={finalizar}>Confirmar Pedido</button>
          </div>
        )}

        {etapa === 'historico' && (
          <div className="container-venda">
            <h2>📋 Meus Pedidos</h2>
            {historico.map((h, i) => (
              <div key={i}>Pedido #{h.id_pedido} - {h.produto}</div>
            ))}
            <button className="btn-p" onClick={() => setEtapa('vitrine')}>Voltar</button>
          </div>
        )}

        {etapa === 'sucesso' && (
          <div className="alerta-s">
            <h2>✅ Sucesso! Pedido #{pedidoFinalizado?.numero}</h2>
            <button onClick={() => setEtapa('vitrine')}>Voltar</button>
          </div>
        )}
      </main>
      <Rodape />
    </div>
  );
}

export default App;
